75	function parseSessionId(input: HookInput): string {
76	  if (typeof input.session_id !== "string" || input.session_id.trim().length === 0) {
77	    throw new Error("capture-session requires a non-empty session_id");
78	  }
79	  return input.session_id;
80	}
81	
82	async function buildManifest(
83	  vaultPath: string,
84	  sessionId: string,
85	  input: HookInput
86	): Promise<SessionManifest> {
87	  const timestamp = new Date().toISOString();
88	  const transcriptPath =
89	    typeof input.transcript_path === "string" && input.transcript_path.length > 0
90	      ? input.transcript_path
91	      : null;
92	  const transcriptInfo = await readTranscriptInfo(transcriptPath);
93	  const gitHead = await headCommit(process.cwd());
94	  const branch = await currentBranch(process.cwd());
95	  const entireCheckpoint = await getHeadCheckpointId(process.cwd());
96	  const filesChanged = await filesChangedForCapture(entireCheckpoint, process.cwd());
97	
98	  const manifest: SessionManifest = {
99	    session_id: sessionId,
100	    timestamp,
101	    transcript_path: transcriptPath,
102	    transcript_hash: transcriptInfo.hash,
103	    transcript_size: transcriptInfo.size,
104	    git_head: gitHead,
105	    branch,
106	    files_changed: filesChanged,
107	    excerpt: transcriptInfo.excerpt,
108	    extracted: false,
109	    decisions: [],
110	    open_threads: [],
111	    tags: [],
112	  };
113	
114	  if (entireCheckpoint) manifest.entire_checkpoint = entireCheckpoint;
115	  if (transcriptInfo.incomplete) manifest.excerpt_incomplete = true;
116	
117	  // Ensure the directory exists even in partially initialized vaults.
118	  mkdirSync(join(vaultPath, "sessions"), { recursive: true });
119	
120	  return manifest;
121	}
122	
123	async function readTranscriptInfo(path: string | null): Promise<{
124	  hash: string | null;
125	  size: number | null;
126	  excerpt: { head: string; tail: string };
127	  incomplete: boolean;
128	}> {
129	  if (!path || !existsSync(path)) {
130	    return { hash: null, size: null, excerpt: { head: "", tail: "" }, incomplete: false };
131	  }
132	
133	  const incomplete = await waitForStableTranscript(path);
134	  const size = safeSize(path);
135	  const [hash, excerpt] = await Promise.all([sha256File(path), extractExcerpt(path)]);
136	  return { hash, size, excerpt, incomplete };
137	}
138	
139	async function waitForStableTranscript(path: string): Promise<boolean> {
140	  const stableMs = parsePositiveInt(
141	    process.env.CAIRN_TRANSCRIPT_STABLE_MS,
142	    TRANSCRIPT_STABLE_MS
143	  );
144	  const first = safeMtimeMs(path);
145	  if (first === null) return false;
146	  await sleep(stableMs);
147	  const second = safeMtimeMs(path);
148	  if (second === null || second === first) return false;
149	  await sleep(stableMs);
150	  const third = safeMtimeMs(path);
151	  return third !== null && third !== second;
152	}
153	
154	function safeMtimeMs(path: string): number | null {
155	  try {
156	    return statSync(path).mtimeMs;
157	  } catch {
158	    return null;
159	  }
160	}
161	
162	function safeSize(path: string): number | null {
163	  try {
164	    return statSync(path).size;
165	  } catch {
166	    return null;
167	  }
168	}
169	
170	function parsePositiveInt(value: string | undefined, fallback: number): number {
171	  if (!value) return fallback;
172	  const parsed = Number.parseInt(value, 10);
173	  return Number.isFinite(parsed) && parsed >= 0 ? parsed : fallback;
174	}
175	
176	function sleep(ms: number): Promise<void> {
177	  return new Promise((resolve) => setTimeout(resolve, ms));
178	}
179	
180	async function filesChangedForCapture(
181	  entireCheckpoint: string | null,
182	  cwd: string
183	): Promise<FileChange[]> {
184	  if (entireCheckpoint && /^[0-9a-f]{7,40}$/i.test(entireCheckpoint)) {
185	    return filesChangedSince(entireCheckpoint, cwd);
186	  }
187	  return uncommittedChanges(cwd);
188	}
189	
190	function manifestExistsForSession(vaultPath: string, sessionId: string): boolean {
191	  const sessionsDir = join(vaultPath, "sessions");
192	  if (!existsSync(sessionsDir)) return false;
193	
194	  const entries = readdirSync(sessionsDir, { withFileTypes: true }).filter(
195	    (entry) => entry.isFile() && entry.name.endsWith(".md")
196	  );
197	  const suffix = manifestFilenameSuffix(sessionId);
198	  const candidates = suffix ? entries.filter((entry) => entry.name.endsWith(suffix)) : entries;
199	  if (suffix && candidates.length === 0) return false;
200	
201	  for (const entry of candidates) {
202	    try {
203	      const manifest = readManifest(join(sessionsDir, entry.name));
204	      if (manifest.session_id === sessionId) return true;
205	    } catch {
206	      // Legacy session files are ignored by the manifest idempotency scan.
207	    }
208	  }
209	  return false;
210	}
211	
212	function manifestFilenameSuffix(sessionId: string): string | null {
213	  try {
214	    return `-${shortSessionId(sessionId)}.md`;
215	  } catch {
216	    return null;
217	  }
218	}
219	
220	async function appendSessionLog(
221	  vaultPath: string,
222	  manifest: SessionManifest
223	): Promise<void> {
224	  const today = manifest.timestamp.slice(0, 10);
225	  const branch = manifest.branch ?? "unknown-branch";
226	  const line = `\n## [${today}] session | ${branch} | ${manifest.files_changed.length} files | ${shortSessionId(manifest.session_id)}\n`;
227	  await withLogLock(vaultPath, async () => {
228	    const logPath = join(vaultPath, "log.md");
229	    if (!existsSync(logPath)) writeFileSync(logPath, "# Vault Log\n");
230	    appendFileSync(logPath, line);
231	  });
232	}
233	
234	function ensureCapturePaths(vaultPath: string): void {
235	  mkdirSync(vaultPath, { recursive: true });
236	  for (const dir of VAULT_DIRS) mkdirSync(join(vaultPath, dir), { recursive: true });
237	  mkdirSync(join(vaultPath, ".cairn", "sessions"), { recursive: true });
238	  if (!existsSync(join(vaultPath, "log.md"))) writeFileSync(join(vaultPath, "log.md"), "# Vault Log\n");
239	}
240	
241	function appendCaptureError(vaultPath: string, err: unknown): void {
242	  mkdirSync(join(vaultPath, ".cairn"), { recursive: true });
243	  const payload = {
244	    ts: new Date().toISOString(),
245	    error: errorMessage(err),
246	    stack: err instanceof Error ? err.stack : undefined,
247	  };
248	  appendFileSync(join(vaultPath, CAPTURE_ERRORS_LOG), `${JSON.stringify(payload)}\n`);
249	}
250	
251	function writeTextAtomic(path: string, content: string): void {
252	  const tmp = `${path}.tmp-${process.pid}-${Date.now()}`;
253	  writeFileSync(tmp, content);
254	  try {
255	    renameSync(tmp, path);
256	  } catch (err) {
257	    if ((err as NodeJS.ErrnoException).code !== "EXDEV") throw err;
258	    copyFileSync(tmp, path);
259	    unlinkSync(tmp);
260	  }
261	}
262	
263	function serializeDateParts(date: string): string {
264	  return date.slice(0, 19).replace(/:/g, "-");
265	}
266	
267	function filenameTimestamp(timestamp: string): string {
268	  return serializeDateParts(timestamp);
269	}
270	
271	function errorMessage(err: unknown): string {
272	  return err instanceof Error ? err.message : String(err);
273	}
274

