1	import {
2	  copyFileSync,
3	  existsSync,
4	  mkdirSync,
5	  readdirSync,
6	  readFileSync,
7	  renameSync,
8	  unlinkSync,
9	  writeFileSync,
10	} from "node:fs";
11	import { basename, isAbsolute, join, resolve } from "node:path";
12	import { parseFrontmatter, serializeFrontmatter } from "./frontmatter";
13	import { sha256File } from "./hash";
14	import {
15	  computeManifestHash,
16	  readManifest,
17	  readSummaryFrontmatter,
18	  writeSummaryFrontmatter,
19	  type SessionManifest,
20	  type SessionSummaryFrontmatter,
21	} from "./manifest";
22	
23	export interface SummarizeOptions {
24	  force?: boolean;
25	  destructive?: boolean;
26	}
27	
28	export interface SummarizeResult {
29	  path: string;
30	  cached: boolean;
31	  degraded: boolean;
32	  chunked: boolean;
33	  truncated_turns: number;
34	}
35	
36	interface SourceText {
37	  text: string;
38	  degraded: boolean;
39	}
40	
41	interface ChunkedText {
42	  chunks: string[];
43	  truncatedTurns: number;
44	}
45	
46	const DEFAULT_CHUNK_BYTES = 60_000;
47	const TRUNCATION_MARKER = "[... oversized turn truncated ...]";
48	
49	export async function summarizeSession(
50	  vaultPath: string,
51	  sessionArg: string,
52	  options: SummarizeOptions = {}
53	): Promise<SummarizeResult> {
54	  const manifestPath = resolveManifestPath(vaultPath, sessionArg);
55	  const manifest = readManifest(manifestPath);
56	  const manifestHash = computeManifestHash(manifest);
57	  const summaryPath = summaryPathForManifest(vaultPath, manifestPath);
58	  mkdirSync(join(vaultPath, "sessions", "summaries"), { recursive: true });
59	
60	  const cached = readCachedSummary(summaryPath);
61	  if (cached && !options.force) {
62	    if (cached.data.user_edited === true) {
63	      return cachedResult(summaryPath, cached.data);
64	    }
65	    if (cached.data.manifest_hash === manifestHash) {
66	      return cachedResult(summaryPath, cached.data);
67	    }
68	    if (manifest.transcript_path === null && cached.body.trim().length > 0) {
69	      return cachedResult(summaryPath, cached.data);
70	    }
71	  }
72	
73	  if (cached && options.force && !options.destructive) {
74	    trashSummary(vaultPath, summaryPath);
75	  }
76	
77	  const source = await loadSourceText(manifest);
78	  const threshold = summarizeThreshold();
79	  const chunkedText = chunkSourceText(source.text, threshold);
80	  const body = await summarizeText(chunkedText.chunks, threshold);
81	  const outputBody = stripModelFrontmatter(body);
82	
83	  writeTextAtomic(
84	    summaryPath,
85	    buildSummaryDocument({
86	      manifestHash,
87	      transcriptHash: manifest.transcript_hash,
88	      degraded: source.degraded,
89	      chunked: chunkedText.chunks.length > 1,
90	      truncatedTurns: chunkedText.truncatedTurns,
91	      body: outputBody,
92	    })
93	  );
94	
95	  return {
96	    path: summaryPath,
97	    cached: false,
98	    degraded: source.degraded,
99	    chunked: chunkedText.chunks.length > 1,
100	    truncated_turns: chunkedText.truncatedTurns,
101	  };
102	}
103	
104	export async function summarizeAll(
105	  vaultPath: string,
106	  options: SummarizeOptions = {},
107	  onProgress?: (line: string) => void
108	): Promise<SummarizeResult[]> {
109	  const sessionsDir = join(vaultPath, "sessions");
110	  const manifests = readdirSync(sessionsDir)
111	    .filter((entry) => entry.endsWith(".md"))
112	    .flatMap((entry) => {
113	      const path = join(sessionsDir, entry);
114	      try {
115	        readManifest(path);
116	        return [path];
117	      } catch {
118	        return [];
119	      }
120	    });
121	  const results: SummarizeResult[] = [];
122	
123	  for (let i = 0; i < manifests.length; i++) {
124	    const manifestPath = manifests[i]!;
125	    onProgress?.(`[${i + 1}/${manifests.length}] summarizing ${basename(manifestPath)}...`);
126	    results.push(await summarizeSession(vaultPath, manifestPath, options));
127	  }
128	
129	  return results;
130	}
131	
132	export function setSummaryPinned(
133	  vaultPath: string,
134	  sessionArg: string,
135	  pinned: boolean
136	): string {
137	  const manifestPath = resolveManifestPath(vaultPath, sessionArg);
138	  const summaryPath = summaryPathForManifest(vaultPath, manifestPath);
139	  const { data, body } = readSummaryFrontmatter(summaryPath);
140	  writeSummaryFrontmatter(summaryPath, { ...data, user_edited: pinned }, body);
141	  return summaryPath;
142	}
143	
144	export function resolveManifestPath(vaultPath: string, sessionArg: string): string {
145	  const direct = isAbsolute(sessionArg) ? sessionArg : resolve(process.cwd(), sessionArg);
146	  if (existsSync(direct)) return direct;
147	
148	  if (sessionArg.startsWith("sessions/")) {
149	    const fromVault = join(vaultPath, sessionArg);
150	    if (existsSync(fromVault)) return fromVault;
151	  }
152	
153	  const fromSessions = join(vaultPath, "sessions", sessionArg);
154	  if (existsSync(fromSessions)) return fromSessions;
155	
156	  if (sessionArg.length < 8) {
157	    throw new Error("session id prefix must be at least 8 characters");
158	  }
159	
160	  const matches: string[] = [];
161	  for (const entry of readdirSync(join(vaultPath, "sessions"))) {
162	    if (!entry.endsWith(".md")) continue;
163	    const path = join(vaultPath, "sessions", entry);
164	    try {
165	      const manifest = readManifest(path);
166	      if (manifest.session_id.startsWith(sessionArg)) matches.push(path);
167	    } catch {
168	      // Legacy session files are not resolvable by manifest prefix.
169	    }
170	  }
171	
172	  if (matches.length === 1) return matches[0]!;
173	  if (matches.length > 1) {
174	    throw new Error(
175	      `ambiguous session id prefix ${sessionArg}; matches: ${matches.map((path) => basename(path)).join(", ")}`
176	    );
177	  }
178	  throw new Error(`no session manifest found for ${sessionArg}`);
179	}
180	
181	function summaryPathForManifest(vaultPath: string, manifestPath: string): string {
182	  return join(vaultPath, "sessions", "summaries", basename(manifestPath));
183	}
184	
185	function readCachedSummary(path: string): ReturnType<typeof readSummaryFrontmatter> | null {
186	  if (!existsSync(path)) return null;
187	  try {
188	    return readSummaryFrontmatter(path);
189	  } catch {
190	    return null;
191	  }
192	}
193	
194	function cachedResult(path: string, data: SessionSummaryFrontmatter): SummarizeResult {
195	  return {
196	    path,
197	    cached: true,
198	    degraded: data.degraded === true,
199	    chunked: data.chunked === true,
200	    truncated_turns: data.truncated_turns ?? 0,
201	  };
202	}
203	
204	async function loadSourceText(manifest: SessionManifest): Promise<SourceText> {
205	  if (manifest.transcript_path) {
206	    const currentHash = await sha256File(manifest.transcript_path);
207	    if (currentHash !== null && currentHash === manifest.transcript_hash) {
208	      return { text: extractTranscriptText(manifest.transcript_path), degraded: false };
209	    }
210	  }
211	
212	  const text =
213	    manifest.excerpt.tail.length > 0
214	      ? `${manifest.excerpt.head}\n\n...\n\n${manifest.excerpt.tail}`
215	      : manifest.excerpt.head;
216	  return { text, degraded: true };
217	}
218	
219	function extractTranscriptText(path: string): string {
220	  const content = readFileSync(path, "utf-8");
221	  const turns: string[] = [];
222	  for (const line of content.split("\n")) {
223	    if (line.trim().length === 0) continue;
224	    const turn = extractTurnText(line);
225	    if (turn) turns.push(turn);
226	  }
227	  return turns.join("\n\n");
228	}
229	
230	function extractTurnText(line: string): string | null {
231	  try {
232	    const parsed = JSON.parse(line) as {
233	      type?: string;
234	      message?: { content?: unknown };
235	    };
236	    if (parsed.type !== "human" && parsed.type !== "assistant") return null;
237	    const label = parsed.type === "human" ? "User" : "Assistant";
238	    const text = extractContentText(parsed.message?.content);
239	    return text.length > 0 ? `## ${label}\n${text}` : null;
240	  } catch {
241	    return null;
242	  }
243	}
244	
245	function extractContentText(content: unknown): string {
246	  if (typeof content === "string") return content;
247	  if (!Array.isArray(content)) return "";
248	  return content
249	    .filter((part): part is { type: string; text: string } => {
250	      if (typeof part !== "object" || part === null) return false;
251	      const record = part as Record<string, unknown>;
252	      return record.type === "text" && typeof record.text === "string";
253	    })
254	    .map((part) => part.text)
255	    .join("\n");
256	}
257	
258	function summarizeThreshold(): number {
259	  const raw = process.env.CAIRN_SUMMARIZE_CHUNK_BYTES;
260	  if (!raw) return DEFAULT_CHUNK_BYTES;
261	  const parsed = Number.parseInt(raw, 10);
262	  return Number.isFinite(parsed) && parsed > 100 ? parsed : DEFAULT_CHUNK_BYTES;
263	}
264	
265	function chunkSourceText(text: string, threshold: number): ChunkedText {
266	  if (Buffer.byteLength(text, "utf-8") <= threshold) {
267	    return { chunks: [text], truncatedTurns: 0 };
268	  }
269	
270	  const units = text.split(/\n{2,}/);
271	  const chunks: string[] = [];
272	  let current = "";
273	  let truncatedTurns = 0;
274	
275	  for (const rawUnit of units) {
276	    let unit = rawUnit;
277	    if (Buffer.byteLength(unit, "utf-8") > threshold) {
278	      unit = truncateToBytes(unit, Math.max(1, threshold - Buffer.byteLength(TRUNCATION_MARKER)));
279	      unit = `${unit}\n${TRUNCATION_MARKER}`;
280	      truncatedTurns++;
281	    }
282	
283	    const next = current.length === 0 ? unit : `${current}\n\n${unit}`;
284	    if (Buffer.byteLength(next, "utf-8") <= threshold) {
285	      current = next;
286	    } else {
287	      if (current.length > 0) chunks.push(current);
288	      current = unit;
289	    }
290	  }
291	
292	  if (current.length > 0) chunks.push(current);
293	  return { chunks: chunks.length > 0 ? chunks : [""], truncatedTurns };
294	}
295	
296	function truncateToBytes(text: string, maxBytes: number): string {
297	  let out = "";
298	  for (const ch of text) {
299	    if (Buffer.byteLength(out + ch, "utf-8") > maxBytes) break;
300	    out += ch;
301	  }
302	  return out;
303	}
304	
305	async function summarizeText(chunks: string[], threshold: number): Promise<string> {
306	  if (chunks.length === 1) return runSummarizer(singlePrompt(chunks[0]!));
307	
308	  const partials: string[] = [];
309	  for (const chunk of chunks) partials.push(await runSummarizer(chunkPrompt(chunk)));
310	  return reduceSummaries(partials, threshold);
311	}
312	
313	async function reduceSummaries(partials: string[], threshold: number): Promise<string> {
314	  if (partials.length === 1) return partials[0]!;
315	
316	  const groups: string[][] = [];
317	  let current: string[] = [];
318	  for (const partial of partials) {
319	    const candidate = [...current, partial];
320	    if (Buffer.byteLength(reducePrompt(candidate), "utf-8") <= threshold || current.length === 0) {
321	      current = candidate;
322	    } else {
323	      groups.push(current);
324	      current = [partial];
325	    }
326	  }
327	  if (current.length > 0) groups.push(current);
328	
329	  const reduced: string[] = [];
330	  for (const group of groups) reduced.push(await runSummarizer(reducePrompt(group)));
331	  return groups.length === 1 ? reduced[0]! : reduceSummaries(reduced, threshold);
332	}
333	
334	async function runSummarizer(prompt: string): Promise<string> {
335	  const command = process.env.CAIRN_SUMMARIZE_COMMAND ?? "claude";
336	  const proc = Bun.spawn([command, "-p", "--model", "haiku"], {
337	    stdin: new Response(prompt),
338	    stdout: "pipe",
339	    stderr: "pipe",
340	  });
341	  const [stdout, stderr] = await Promise.all([
342	    new Response(proc.stdout).text(),
343	    new Response(proc.stderr).text(),
344	  ]);
345	  const exitCode = await proc.exited;
346	  if (exitCode !== 0) {
347	    throw new Error(stderr.trim() || `summarizer exited ${exitCode}`);
348	  }
349	  return stdout.trim();
350	}
351	
352	function singlePrompt(text: string): string {
353	  return `${promptPreamble()}\n\nSESSION TRANSCRIPT:\n\n${text}\n`;
354	}
355	
356	function chunkPrompt(text: string): string {
357	  return `${promptPreamble()}\n\nSummarize this chunk of a larger session. Preserve concrete decisions, files, and extraction candidates.\n\nSESSION CHUNK:\n\n${text}\n`;
358	}
359	
360	function reducePrompt(partials: string[]): string {
361	  return `${promptPreamble()}\n\nMerge these partial session summaries into one coherent final summary. Resolve duplicates and contradictions.\n\nPARTIAL SUMMARIES:\n\n${partials.join("\n\n---\n\n")}\n`;
362	}
363	
364	function promptPreamble(): string {
365	  return `You are the Cairn session summarizer. Return markdown with "## Summary" and "## Extraction Candidates" sections. Do not wrap the output in a code fence.`;
366	}
367	
368	function stripModelFrontmatter(output: string): string {
369	  try {
370	    const parsed = parseFrontmatter(output);
371	    return parsed.body.trim().length > 0 ? parsed.body : output.trim();
372	  } catch {
373	    return output.trim();
374	  }
375	}
376	
377	function buildSummaryDocument(input: {
378	  manifestHash: string;
379	  transcriptHash: string | null;
380	  degraded: boolean;
381	  chunked: boolean;
382	  truncatedTurns: number;
383	  body: string;
384	}): string {
385	  const frontmatter: SessionSummaryFrontmatter = {
386	    manifest_hash: input.manifestHash,
387	    transcript_hash: input.transcriptHash,
388	    generated_at: new Date().toISOString(),
389	    degraded: input.degraded || undefined,
390	    chunked: input.chunked || undefined,
391	    truncated_turns: input.truncatedTurns > 0 ? input.truncatedTurns : undefined,
392	  };
393	  return serializeFrontmatter(
394	    frontmatter as unknown as Record<string, unknown>,
395	    `${input.body.trim()}\n`
396	  );
397	}
398	
399	function trashSummary(vaultPath: string, summaryPath: string): void {
400	  const trashDir = join(vaultPath, "sessions", ".trash", "summaries");
401	  mkdirSync(trashDir, { recursive: true });
402	  const stamp = new Date().toISOString().slice(0, 19).replace(/:/g, "-");
403	  const target = join(trashDir, `${basename(summaryPath, ".md")}-${stamp}.md`);
404	  moveFile(summaryPath, target);
405	}
406	
407	function moveFile(from: string, to: string): void {
408	  try {
409	    renameSync(from, to);
410	  } catch (err) {
411	    if ((err as NodeJS.ErrnoException).code !== "EXDEV") throw err;
412	    copyFileSync(from, to);
413	    unlinkSync(from);
414	  }
415	}
416	
417	function writeTextAtomic(path: string, content: string): void {
418	  const tmp = `${path}.tmp-${process.pid}-${Date.now()}`;
419	  writeFileSync(tmp, content);
420	  try {
421	    renameSync(tmp, path);
422	  } catch (err) {
423	    if ((err as NodeJS.ErrnoException).code !== "EXDEV") throw err;
424	    copyFileSync(tmp, path);
425	    unlinkSync(tmp);
426	  }
427	}
428

