function rewriteLineSkippingInlineCode(line: string, sourceFile: string): string {
  const parts: string[] = [];
  let i = 0;
  while (i < line.length) {
    if (line[i] === "`") {
      let runLen = 0;
      while (i + runLen < line.length && line[i + runLen] === "`") runLen++;
      const open = "`".repeat(runLen);
      const closeIdx = line.indexOf(open, i + runLen);
      if (closeIdx === -1) {
        parts.push(rewriteSegment(line.slice(i), sourceFile));
        i = line.length;
      } else {
        parts.push(line.slice(i, closeIdx + runLen));
