function rewriteBody(body: string, sourceFile: string): string {
  const lines = body.split("\n");
  let inFence = false;
  let fenceChar = "";
  let fenceLen = 0;

  return lines
    .map((line) => {
      const fenceMatch = line.match(/^\s*(`{3,}|~{3,})/);
      if (fenceMatch) {
        const marker = fenceMatch[1]!;
        const ch = marker[0]!;
        const len = marker.length;
        if (!inFence) {
          inFence = true;
          fenceChar = ch;
          fenceLen = len;
          return line;
        }
        if (ch === fenceChar && len >= fenceLen) {
          inFence = false;
          fenceChar = "";
          fenceLen = 0;
          return line;
        }
      }
      if (inFence) return line;
      return rewriteLineSkippingInlineCode(line, sourceFile);
    })
    .join("\n");
}

