#!/usr/bin/env bun
/**
 * One-shot rewriter: rewrite every body wikilink in ~/cairn to
 * [[kebab-filename|Display Title]] form.
 *
 * Frontmatter is preserved byte-for-byte; only document bodies are touched.
 * Run with no flags for preview, --apply to write, --apply --yes to skip prompt.
 */
import { readdirSync, readFileSync, writeFileSync, mkdirSync, copyFileSync, existsSync } from "node:fs";
import { join } from "node:path";
import { homedir } from "node:os";
import { parse as yamlParse } from "yaml";

const VAULT = process.env.CAIRN_VAULT ?? join(homedir(), "cairn");
const WIKI_DIR = join(VAULT, "wiki");
const ROOT_FILES = ["index.md", "log.md", "context.md", "CAIRN.md"];
const APPLY = process.argv.includes("--apply");
const YES = process.argv.includes("--yes");

interface PageInfo {
  filename: string;
  title: string | null;
  aliases: string[];
}

function splitFrontmatter(content: string): { fm: string; body: string } {
  if (!content.startsWith("---\n") && !content.startsWith("---\r\n")) {
    return { fm: "", body: content };
  }
  const after = content.slice(3).replace(/^\r?\n/, "");
  const m = after.match(/\r?\n---\r?\n?/);
  if (!m || m.index === undefined) return { fm: "", body: content };
  const fmEnd = content.length - after.length + m.index + m[0].length;
  return { fm: content.slice(0, fmEnd), body: content.slice(fmEnd) };
}

function parseFmData(fm: string): Record<string, unknown> {
  if (!fm) return {};
  const inner = fm.replace(/^---\r?\n/, "").replace(/\r?\n---\r?\n?$/, "");
  try {
    return (yamlParse(inner) ?? {}) as Record<string, unknown>;
  } catch {
    return {};
  }
}

const pages: PageInfo[] = [];
for (const file of readdirSync(WIKI_DIR)) {
  if (!file.endsWith(".md")) continue;
  const content = readFileSync(join(WIKI_DIR, file), "utf-8");
  const { fm } = splitFrontmatter(content);
  const data = parseFmData(fm);
  pages.push({
    filename: file.slice(0, -3),
    title: typeof data.title === "string" ? data.title : null,
    aliases: Array.isArray(data.aliases)
      ? data.aliases.filter((a): a is string => typeof a === "string")
      : [],
  });
}

const filenameSet = new Set(pages.map((p) => p.filename));
const titleIndex = new Map<string, string[]>();
const aliasIndex = new Map<string, string[]>();
const titleByFile = new Map<string, string>();

for (const p of pages) {
  if (p.title) {
    titleByFile.set(p.filename, p.title);
    const arr = titleIndex.get(p.title) ?? [];
    arr.push(p.filename);
    titleIndex.set(p.title, arr);
  }
  for (const a of p.aliases) {
    const arr = aliasIndex.get(a) ?? [];
    arr.push(p.filename);
    aliasIndex.set(a, arr);
  }
}

type Resolution =
  | { kind: "filename"; file: string }
  | { kind: "title"; file: string }
  | { kind: "alias"; file: string }
  | { kind: "ambiguous"; via: "title" | "alias"; candidates: string[] }
  | { kind: "unresolved" };

function resolveTarget(target: string): Resolution {
  if (filenameSet.has(target)) return { kind: "filename", file: target };

  const t = titleIndex.get(target);
  if (t && t.length === 1) return { kind: "title", file: t[0]! };
  if (t && t.length > 1) return { kind: "ambiguous", via: "title", candidates: t };

  const a = aliasIndex.get(target);
  if (a && a.length === 1) return { kind: "alias", file: a[0]! };
  if (a && a.length > 1) return { kind: "ambiguous", via: "alias", candidates: a };

  return { kind: "unresolved" };
}

interface Stats {
  rewritten: number;
  rewrittenAddedDisplay: number;
  alreadyCorrect: number;
  pathStyle: number;
  ambiguous: { from: string; via: string; candidates: string[]; in: string }[];
  unresolved: Map<string, Set<string>>;
  noTitleForFilename: { from: string; in: string }[];
}

const stats: Stats = {
  rewritten: 0,
  rewrittenAddedDisplay: 0,
  alreadyCorrect: 0,
  pathStyle: 0,
  ambiguous: [],
  unresolved: new Map(),
  noTitleForFilename: [],
};

const WIKILINK_RE = /(!?)\[\[([^\]]+)\]\]/g;

function rewriteBody(body: string, sourceFile: string): string {
  return body.replace(WIKILINK_RE, (match, embed: string, inner: string) => {
    const pipeIdx = inner.indexOf("|");
    const targetPart = pipeIdx === -1 ? inner : inner.slice(0, pipeIdx);
    const display = pipeIdx === -1 ? null : inner.slice(pipeIdx + 1);

    const hashIdx = targetPart.indexOf("#");
    const target = hashIdx === -1 ? targetPart : targetPart.slice(0, hashIdx);
    const fragment = hashIdx === -1 ? "" : targetPart.slice(hashIdx);

    if (target.includes("/")) {
      stats.pathStyle++;
      return match;
    }

    const r = resolveTarget(target);
    if (r.kind === "ambiguous") {
      stats.ambiguous.push({ from: target, via: r.via, candidates: r.candidates, in: sourceFile });
      return match;
    }
    if (r.kind === "unresolved") {
      const set = stats.unresolved.get(target) ?? new Set();
      set.add(sourceFile);
      stats.unresolved.set(target, set);
      return match;
    }

    const file = r.file;

    if (target === file) {
      if (display !== null) {
        stats.alreadyCorrect++;
        return match;
      }
      const title = titleByFile.get(file);
      if (!title) {
        stats.noTitleForFilename.push({ from: target, in: sourceFile });
        return match;
      }
      stats.rewrittenAddedDisplay++;
      return `${embed}[[${file}${fragment}|${title}]]`;
    }

    const newDisplay = display ?? target;
    stats.rewritten++;
    return `${embed}[[${file}${fragment}|${newDisplay}]]`;
  });
}

interface FileChange {
  path: string;
  before: string;
  after: string;
}
const changes: FileChange[] = [];

function processFile(absPath: string, label: string): void {
  if (!existsSync(absPath)) return;
  const content = readFileSync(absPath, "utf-8");
  const { fm, body } = splitFrontmatter(content);
  const newBody = rewriteBody(body, label);
  if (newBody !== body) {
    changes.push({ path: absPath, before: content, after: fm + newBody });
  }
}

for (const file of readdirSync(WIKI_DIR)) {
  if (!file.endsWith(".md")) continue;
  processFile(join(WIKI_DIR, file), `wiki/${file}`);
}
for (const root of ROOT_FILES) {
  processFile(join(VAULT, root), root);
}

console.log(`\nVault: ${VAULT}`);
console.log(`Pages indexed: ${pages.length}`);
console.log(`\n--- Rewrite stats ---`);
console.log(`Rewritten (title/alias → kebab|display): ${stats.rewritten}`);
console.log(`Rewritten (added display from frontmatter title): ${stats.rewrittenAddedDisplay}`);
console.log(`Already correct (kebab|display): ${stats.alreadyCorrect}`);
console.log(`Path-style (raw/...) skipped: ${stats.pathStyle}`);
console.log(`Files changed: ${changes.length}`);

if (stats.ambiguous.length > 0) {
  console.log(`\n--- Ambiguous (skipped) ---`);
  for (const a of stats.ambiguous.slice(0, 20)) {
    console.log(`  [[${a.from}]] in ${a.in}: ${a.via} matches ${a.candidates.join(", ")}`);
  }
  if (stats.ambiguous.length > 20) console.log(`  ... and ${stats.ambiguous.length - 20} more`);
}

if (stats.unresolved.size > 0) {
  console.log(`\n--- Unresolved (broken — left alone) ---`);
  const entries = [...stats.unresolved.entries()].sort((a, b) => b[1].size - a[1].size);
  for (const [target, files] of entries.slice(0, 30)) {
    console.log(`  [[${target}]] — ${files.size} file(s)`);
  }
  if (entries.length > 30) console.log(`  ... and ${entries.length - 30} more`);
}

if (stats.noTitleForFilename.length > 0) {
  console.log(`\n--- Filename-form links to pages with no title (skipped) ---`);
  for (const n of stats.noTitleForFilename.slice(0, 10)) {
    console.log(`  [[${n.from}]] in ${n.in}`);
  }
}

if (!APPLY) {
  console.log(`\n(Preview only. Re-run with --apply --yes to write changes.)`);
  process.exit(0);
}

if (!YES) {
  console.log(`\nRefusing to apply without --yes. Re-run with --apply --yes.`);
  process.exit(2);
}

const stamp = new Date().toISOString().slice(0, 19).replace(/:/g, "-");
const backupRoot = join(VAULT, ".cairn", "migration-backups", `links-${stamp}`);
mkdirSync(backupRoot, { recursive: true });

for (const c of changes) {
  const rel = c.path.startsWith(VAULT + "/") ? c.path.slice(VAULT.length + 1) : c.path;
  const backupPath = join(backupRoot, rel);
  mkdirSync(join(backupPath, ".."), { recursive: true });
  copyFileSync(c.path, backupPath);
  writeFileSync(c.path, c.after);
}

console.log(`\nApplied ${changes.length} files. Backup at:`);
console.log(`  ${backupRoot}`);

