#!/usr/bin/env bun
import { defineCommand, runMain } from "citty";
import { VERSION } from "./lib/constants";

const main = defineCommand({
  meta: {
    name: "cairn",
    version: VERSION,
    description: "A persistent memory plugin for Claude Code",
  },
  subCommands: {
